import {
  ChangeDetectionStrategy,
  Component,
  computed,
  forwardRef,
  input,
  model,
  output,
} from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { TABS_CONTEXT, type TabsContext } from './tabs.context';
import type { TabsVariants } from './tabs.variants';

let _tabsCounter = 0;

@Component({
  selector: 'n-tabs',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    '[class]': 'classes()',
    '[attr.data-orientation]': 'nOrientation()',
    'data-slot': 'root',
  },
  providers: [
    {
      provide: TABS_CONTEXT,
      useFactory: (cmp: TabsComponent) => cmp.context,
      deps: [forwardRef(() => TabsComponent)],
    },
  ],
})
export class TabsComponent {
  readonly nValue        = model<string>('');
  readonly nDefaultValue = input<string>('');
  readonly nOrientation  = input<'horizontal' | 'vertical'>('horizontal');
  readonly nVariant      = input<TabsVariants['nVariant']>('pills');
  readonly nStretch      = input<boolean>(false);
  readonly nClass        = input<string>('');

  readonly nValueChange = output<string>();

  private readonly _tabId = `n-tabs-${++_tabsCounter}`;

  private readonly _activeValue = computed(() => this.nValue() || this.nDefaultValue());

  protected readonly classes = computed(() =>
    mergeClasses(
      'flex',
      this.nOrientation() === 'vertical' ? 'flex-row items-start gap-0' : 'flex-col',
      this.nClass(),
    ),
  );

  readonly context: TabsContext = {
    tabId:        this._tabId,
    activeValue:  this._activeValue,
    orientation:  this.nOrientation,
    variant:      this.nVariant,
    stretch:      this.nStretch,
    setActive: (value: string) => {
      this.nValue.set(value);
      this.nValueChange.emit(value);
    },
    getTriggerId: (value: string) => `${this._tabId}-trigger-${value.replace(/\s+/g, '-')}`,
    getPanelId:   (value: string) => `${this._tabId}-panel-${value.replace(/\s+/g, '-')}`,
  };
}

import {
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  afterEveryRender,
  computed,
  inject,
  input,
  signal,
} from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { TABS_CONTEXT } from './tabs.context';
import { tabsListVariants } from './tabs.variants';

@Component({
  selector: 'n-tabs-list',
  standalone: true,
  template: `
    @if (showIndicator()) {
      <span
        aria-hidden="true"
        [class]="indicatorClass()"
        [style.left]="isHorizontal() ? indLeft() : null"
        [style.width]="isHorizontal() ? indWidth() : null"
        [style.top]="!isHorizontal() ? indTop() : null"
        [style.height]="!isHorizontal() ? indHeight() : null"
        [style.opacity]="indReady() ? '1' : '0'"
      ></span>
    }
    <ng-content />
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    '[class]': 'classes()',
    'role': 'tablist',
    '[attr.aria-orientation]': 'ctx.orientation()',
    'data-slot': 'list',
  },
})
export class TabsListComponent {
  private readonly _el  = inject(ElementRef<HTMLElement>);
  protected readonly ctx = inject(TABS_CONTEXT);

  readonly nClass = input<string>('');

  protected readonly indLeft   = signal('0px');
  protected readonly indTop    = signal('0px');
  protected readonly indWidth  = signal('0px');
  protected readonly indHeight = signal('0px');
  protected readonly indReady  = signal(false);
  private   readonly _animated = signal(false);

  protected readonly isHorizontal  = computed(() => this.ctx.orientation() === 'horizontal');
  protected readonly showIndicator = computed(() =>
    this.ctx.variant() === 'pills' || this.ctx.variant() === 'line',
  );

  protected readonly classes = computed(() =>
    mergeClasses(
      tabsListVariants({
        nVariant:     this.ctx.variant(),
        nOrientation: this.ctx.orientation(),
      }),
      this.ctx.stretch() ? 'w-full' : '',
      this.nClass(),
    ),
  );

  protected readonly indicatorClass = computed(() => {
    const variant  = this.ctx.variant();
    const vertical = !this.isHorizontal();
    const animate  = this._animated()
      ? 'transition-[left,top,width,height] duration-200 ease-out'
      : '';

    if (variant === 'pills') {
      return mergeClasses(
        'absolute z-0 rounded-md bg-background shadow-sm pointer-events-none',
        vertical ? 'inset-x-1' : 'inset-y-1',
        animate,
      );
    }

    // line
    return mergeClasses(
      'absolute z-0 bg-primary pointer-events-none',
      vertical ? 'right-0 w-0.5' : 'bottom-0 h-0.5',
      animate,
    );
  });

  constructor() {
    afterEveryRender(() => {
      if (!this.showIndicator()) return;
      this._measure();
    });
  }

  private _measure(): void {
    const host   = this._el.nativeElement as HTMLElement;
    const active = host.querySelector<HTMLElement>('[role="tab"][data-state="active"]');
    if (!active) return;

    const listRect   = host.getBoundingClientRect();
    const activeRect = active.getBoundingClientRect();

    if (this.isHorizontal()) {
      this.indLeft.set(`${activeRect.left - listRect.left}px`);
      this.indWidth.set(`${activeRect.width}px`);
    } else {
      this.indTop.set(`${activeRect.top - listRect.top}px`);
      this.indHeight.set(`${activeRect.height}px`);
    }

    if (!this.indReady()) this.indReady.set(true);

    // enable transition only after first paint so indicator doesn't animate from (0,0)
    if (!this._animated()) setTimeout(() => this._animated.set(true));
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  computed,
  inject,
  input,
} from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { TABS_CONTEXT } from './tabs.context';
import { tabsTriggerVariants, type TabsTriggerVariants } from './tabs.variants';

@Component({
  selector: 'n-tabs-trigger, button[n-tabs-trigger]',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    '[class]': 'classes()',
    'role': 'tab',
    '[attr.id]': 'triggerId()',
    '[attr.tabindex]': 'isActive() ? "0" : "-1"',
    '[attr.aria-selected]': 'isActive()',
    '[attr.aria-controls]': 'panelId()',
    '[attr.disabled]': 'nDisabled() ? true : null',
    '[attr.aria-disabled]': 'nDisabled() ? true : null',
    '[attr.data-state]': 'isActive() ? "active" : "inactive"',
    '[attr.data-disabled]': 'nDisabled() ? "" : null',
    'data-slot': 'trigger',
    '(click)': 'handleClick()',
    '(keydown)': 'handleKeydown($event)',
  },
})
export class TabsTriggerComponent {
  private readonly _ctx = inject(TABS_CONTEXT);
  private readonly _el  = inject(ElementRef<HTMLElement>);

  readonly nValue    = input.required<string>();
  readonly nDisabled = input<boolean>(false);
  readonly nSize     = input<TabsTriggerVariants['nSize']>('default');
  readonly nClass    = input<string>('');

  protected readonly isActive   = computed(() => this._ctx.activeValue() === this.nValue());
  protected readonly triggerId  = computed(() => this._ctx.getTriggerId(this.nValue()));
  protected readonly panelId    = computed(() => this._ctx.getPanelId(this.nValue()));

  protected readonly classes = computed(() =>
    mergeClasses(
      tabsTriggerVariants({
        nVariant:     this._ctx.variant(),
        nSize:        this.nSize(),
        nOrientation: this._ctx.orientation(),
      }),
      this._ctx.stretch() ? 'flex-1' : '',
      this.nClass(),
    ),
  );

  protected handleClick(): void {
    if (this.nDisabled()) return;
    this._ctx.setActive(this.nValue());
  }

  protected handleKeydown(event: KeyboardEvent): void {
    if (this.nDisabled()) return;

    const isHorizontal = this._ctx.orientation() === 'horizontal';
    const prevKey = isHorizontal ? 'ArrowLeft' : 'ArrowUp';
    const nextKey = isHorizontal ? 'ArrowRight' : 'ArrowDown';

    if (![prevKey, nextKey, 'Home', 'End'].includes(event.key)) return;

    event.preventDefault();

    const tablist = this._el.nativeElement.closest('[role="tablist"]');
    if (!tablist) return;

    const triggers = Array.from(tablist.querySelectorAll('[role="tab"]:not([disabled])')) as HTMLElement[];
    const currentIndex = triggers.indexOf(this._el.nativeElement);
    if (currentIndex === -1) return;

    let targetIndex: number;
    if (event.key === prevKey) {
      targetIndex = (currentIndex - 1 + triggers.length) % triggers.length;
    } else if (event.key === nextKey) {
      targetIndex = (currentIndex + 1) % triggers.length;
    } else if (event.key === 'Home') {
      targetIndex = 0;
    } else {
      targetIndex = triggers.length - 1;
    }

    const target = triggers[targetIndex];
    target?.focus();
    target?.click();
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  input,
} from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { TABS_CONTEXT } from './tabs.context';

@Component({
  selector: 'n-tabs-content',
  standalone: true,
  template: `
    <div [class]="contentClasses()" data-slot="content">
      <ng-content />
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    'role': 'tabpanel',
    '[attr.id]': 'panelId()',
    '[attr.aria-labelledby]': 'triggerId()',
    '[attr.data-state]': 'isActive() ? "active" : "inactive"',
    '[attr.tabindex]': 'isActive() ? "0" : "-1"',
    '[attr.hidden]': '!isActive() ? "" : null',
  },
})
export class TabsContentComponent {
  private readonly _ctx = inject(TABS_CONTEXT);

  readonly nValue = input.required<string>();
  readonly nClass = input<string>('');

  protected readonly isActive  = computed(() => this._ctx.activeValue() === this.nValue());
  protected readonly triggerId = computed(() => this._ctx.getTriggerId(this.nValue()));
  protected readonly panelId   = computed(() => this._ctx.getPanelId(this.nValue()));

  protected readonly contentClasses = computed(() =>
    mergeClasses('focus-visible:outline-none', this.nClass()),
  );
}

import { InjectionToken, Signal } from '@angular/core';
import type { TabsVariants } from './tabs.variants';

export interface TabsContext {
  readonly tabId: string;
  readonly activeValue: Signal<string>;
  readonly orientation: Signal<'horizontal' | 'vertical'>;
  readonly variant: Signal<TabsVariants['nVariant']>;
  readonly stretch: Signal<boolean>;
  setActive(value: string): void;
  getTriggerId(value: string): string;
  getPanelId(value: string): string;
}

export const TABS_CONTEXT = new InjectionToken<TabsContext>('TabsContext');

import { cva, type VariantProps } from 'class-variance-authority';

export const tabsListVariants = cva('relative flex shrink-0', {
  variants: {
    nVariant: {
      pills: 'items-center gap-1 bg-muted p-1 rounded-lg',
      line:  '',
      boxed: 'items-stretch overflow-hidden',
    },
    nOrientation: {
      horizontal: 'flex-row',
      vertical:   'flex-col',
    },
  },
  compoundVariants: [
    { nVariant: 'line',  nOrientation: 'horizontal', class: 'border-b border-border' },
    { nVariant: 'line',  nOrientation: 'vertical',   class: 'border-r border-border' },
    { nVariant: 'boxed', nOrientation: 'horizontal', class: 'border border-b-0 border-border rounded-t-lg' },
    { nVariant: 'boxed', nOrientation: 'vertical',   class: 'border border-r-0 border-border rounded-l-lg rounded-tr-none' },
  ],
  defaultVariants: { nVariant: 'pills', nOrientation: 'horizontal' },
});

export const tabsTriggerVariants = cva(
  'relative z-[1] inline-flex items-center justify-center gap-1.5 whitespace-nowrap text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 cursor-pointer select-none',
  {
    variants: {
      nVariant: {
        // active bg/shadow removed — animated indicator in TabsListComponent provides it
        pills: [
          'rounded-md px-3 py-1.5 text-muted-foreground',
          'hover:text-foreground',
          'data-[state=active]:text-foreground',
        ],
        // active border removed — animated indicator provides the underline
        line: 'px-3 py-2 text-muted-foreground hover:text-foreground data-[state=active]:text-foreground',
        boxed: [
          'px-4 py-2 bg-muted/50 text-muted-foreground border-border',
          'hover:bg-muted hover:text-foreground',
          'data-[state=active]:bg-background data-[state=active]:text-foreground',
        ],
      },
      nSize: {
        sm:      'text-xs px-2 py-1',
        default: '',
        lg:      'text-base px-4 py-2.5',
      },
      nOrientation: {
        horizontal: '',
        vertical:   '',
      },
    },
    compoundVariants: [
      { nVariant: 'boxed', nOrientation: 'horizontal', class: 'border-r last:border-r-0' },
      { nVariant: 'boxed', nOrientation: 'vertical',   class: 'border-b last:border-b-0' },
    ],
    defaultVariants: { nVariant: 'pills', nSize: 'default', nOrientation: 'horizontal' },
  },
);

export type TabsVariants = VariantProps<typeof tabsListVariants>;
export type TabsTriggerVariants = VariantProps<typeof tabsTriggerVariants>;

export { TabsComponent } from './tabs.component';
export { TabsListComponent } from './tabs-list.component';
export { TabsTriggerComponent } from './tabs-trigger.component';
export { TabsContentComponent } from './tabs-content.component';
export { TABS_CONTEXT } from './tabs.context';
export type { TabsContext } from './tabs.context';
export { tabsListVariants, tabsTriggerVariants } from './tabs.variants';
export type { TabsVariants, TabsTriggerVariants } from './tabs.variants';

